import React, { useEffect } from 'react';
import { View, Text, Button, StyleSheet } from 'react-native';
import { secureStorage } from './utils/secureStorage';
import { useUserProfile, useAuthTokens } from './hooks/useSecureStorage';

const ExampleUsage = () => {
  const { profile, loading: profileLoading, saveProfile, clearProfile } = useUserProfile();
  const { tokens, loading: tokensLoading, saveTokens, clearTokens } = useAuthTokens();

  const handleSaveProfile = async () => {
    const userProfile = {
      id: '12345',
      name: 'John Doe',
      email: 'john@example.com',
      phone: '+1234567890',
      address: '123 Main St',
    };
    await saveProfile(userProfile);
  };

  const handleSavePayment = async () => {
    const paymentInfo = {
      cardNumber: '4111111111111111',
      cardHolder: 'John Doe',
      expiryDate: '12/25',
      cvv: '123',
    };
    await secureStorage.savePaymentInfo(paymentInfo);
  };

  const handleSaveTokens = async () => {
    await saveTokens(
      'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9...',
      'refresh_token_here'
    );
  };

  const handleClearAll = async () => {
    await secureStorage.clearAll();
    await clearProfile();
    await clearTokens();
  };

  if (profileLoading || tokensLoading) {
    return <Text>Loading...</Text>;
  }

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Secure Storage Example</Text>
      
      <Text style={styles.label}>User Profile:</Text>
      <Text>{profile ? JSON.stringify(profile, null, 2) : 'No profile saved'}</Text>
      
      <Text style={styles.label}>Auth Token:</Text>
      <Text>{tokens.authToken ? 'Token exists' : 'No token'}</Text>
      
      <Button title="Save Profile" onPress={handleSaveProfile} />
      <Button title="Save Payment Info" onPress={handleSavePayment} />
      <Button title="Save Tokens" onPress={handleSaveTokens} />
      <Button title="Clear Profile" onPress={clearProfile} />
      <Button title="Clear Tokens" onPress={clearTokens} />
      <Button title="Clear All" onPress={handleClearAll} />
    </View>
  );
};

